    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri data = intent.getData();
            if (data != null && "myapp".equals(data.getScheme())) {
                String path = data.getPath();
                // Handle the deep link by parsing the URL and navigating to the appropriate screen
                switch (path) {
                    case "/profile/*":
                        // Navigate to profile screen with ID extracted from the path
                        String id = path.replace("/", "").trim();
                        openProfileScreen(id);
                        break;
                    case "/payment/confirm":
                        // Navigate to payment confirmation screen
                        openPaymentConfirmationScreen();
                        break;
                    case "/admin/settings":
                        // Navigate to admin settings screen
                        openAdminSettingsScreen();
                        break;
                }
            }
        }
    }

